/bin/bash -lc "node <<'NODE'
const fs=require('fs');
const report=fs.readFileSync('REPORT.md','utf8');
const summary=JSON.parse(fs.readFileSync('summary.json','utf8'));
const headings=report.split(/\\r?\\n/).filter(x=>/"'^#{1,6} /.test(x));
const bullets=report.split(/'"\\r?\\n/).filter(x=>x.startsWith('- '));
const forbidden=/\\b(leverage|delve|robust|seamless|revolutionize)\\b/i;
const expectedHeadings=['## Overview','## Top Products','## Regional Performance','## Recommendations'];
const expectedKeys=['total_revenue','orders','median_order_value','top_product_by_revenue','revenue_by_region'];
const words=report.trim().split(/\\s+/).length;
const checks={headings:JSON.stringify(headings)===JSON.stringify(expectedHeadings),words,word_limit:words<=250,three_bullets:bullets.length===3,bullet_word_counts:bullets.map(x=>x.trim().split(/\\s+/).length),bullets_within_limit:bullets.every(x=>x.trim().split(/\\s+/).length<=25),forbidden_absent:"'!forbidden.test(report),summary_keys:JSON.stringify(Object.keys(summary))===JSON.stringify(expectedKeys),region_keys:Object.keys(summary.revenue_by_region)};
console.log(JSON.stringify(checks,null,2));
if(!checks.headings||!checks.word_limit||!checks.three_bullets||!checks.bullets_within_limit||!checks.forbidden_absent||!checks.summary_keys)process.exit(1);
NODE'

